#include <stdio.h>

int ff[] = { 1, 2, 6, 24, 120, 720, 5040, 40320, 362880, 3628800, 39916800 };

int rank(int *a, int n) {
	int i, j, cnt, r;
	char used[12] = { 0 };

	r = 0;
	for (i = 0; i < n; i++) {
		cnt = 0;
		for (j = 1; j <= a[i]; j++)
			cnt += !used[j];
		r += ff[(n - i - 1) - 1] * (cnt - 1);
		used[a[i]] = 1;
	}
	return r;
}

int main() {
	int i, j, n, k, k1, k2, player, end;
	static int a[11]; 
	static char used[39916800];

	scanf("%d", &n);
	scanf("%d", &k1);
	for (i = 0; i < k1; i++)
		scanf("%d", &a[i]);
	a[k1] = n + 1;
	scanf("%d", &k2);
	for (i = 0; i < k2; i++)
		scanf("%d", &a[k1 + i + 1]);
	end = 1;
	for (k = 1; ; k++) {
		int r = rank(a, n + 1);
		int top1, top2;

		if (a[0] == n + 1) {
			player = 2;
			k--;
			break;
		}
		if (a[n] == n + 1) {
			player = 1;
			k--;
			break;
		}
		if (used[r]) {
			end = 0;
			break;
		}
		used[r] = 1;
		for (i = 0; i <= n; i++)
			if (a[i] == n + 1)
				break;
		top1 = a[0], top2 = a[i + 1];
		for (j = 1; j < i; j++)
			a[j - 1] = a[j];
		for (j = i + 2; j <= n; j++)
			a[j - 1] = a[j];
		if (top1 < top2) {
			a[i - 1] = n + 1;
			a[i] = a[i + 1]; 
			for (j = i + 2; j <= n; j++)
				a[j - 1] = a[j];
			a[n - 1] = top1;
			a[n] = top2;
		} else {
			for (j = n - 2; j >= i; j--)
				a[j + 1] = a[j];
			a[i + 1] = n + 1;
			a[i - 1] = top2;
			a[i] = top1;
		}
	}
	if (end)
		printf("%d %d\n", k, player);
	else
		printf("-1\n");
	return 0;
}

